// lib/payment_module/services/encryption_service.dart

import 'dart:convert';
import 'dart:math';
import 'dart:typed_data';
import 'package:crypto/crypto.dart';

class EncryptionService {
  static EncryptionService? _instance;

  EncryptionService._();

  factory EncryptionService() {
    _instance ??= EncryptionService._();
    return _instance!;
  }

  String generateNonce([int length = 32]) {
    const charset = 'ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789';
    final random = Random.secure();
    return List.generate(length, (_) => charset[random.nextInt(charset.length)]).join();
  }

  String hashData(String data) {
    final bytes = utf8.encode(data);
    final digest = sha256.convert(bytes);
    return digest.toString();
  }

  String hmacSign(String data, String key) {
    final keyBytes = utf8.encode(key);
    final dataBytes = utf8.encode(data);
    final hmacSha256 = Hmac(sha256, keyBytes);
    final digest = hmacSha256.convert(dataBytes);
    return digest.toString();
  }

  String maskCardNumber(String cardNumber) {
    final cleaned = cardNumber.replaceAll(RegExp(r'\s+'), '');
    if (cleaned.length < 4) return '****';
    return '**** **** **** ${cleaned.substring(cleaned.length - 4)}';
  }

  String maskEmail(String email) {
    final parts = email.split('@');
    if (parts.length != 2) return '***@***';
    final name = parts[0];
    final domain = parts[1];
    final maskedName = name.length > 2
        ? '${name[0]}${'*' * (name.length - 2)}${name[name.length - 1]}'
        : '**';
    return '$maskedName@$domain';
  }

  Map<String, String> generateSecureHeaders(String apiKey) {
    final timestamp = DateTime.now().millisecondsSinceEpoch.toString();
    final nonce = generateNonce();
    final signature = hmacSign('$timestamp:$nonce', apiKey);

    return {
      'X-Timestamp': timestamp,
      'X-Nonce': nonce,
      'X-Signature': signature,
    };
  }
}


