import 'dart:convert';
import 'package:http/http.dart' as http;
import '../config/payment_config.dart';
import '../models/payment_models.dart';
import 'encryption_service.dart';
import 'secure_storage_service.dart';

class PaymentGatewayService {
  final PaymentConfig config;
  final EncryptionService _encryptionService;
  final SecureStorageService _secureStorage;
  final http.Client _httpClient;

  PaymentGatewayService({
    required this.config,
    http.Client? httpClient,
  })  : _encryptionService = EncryptionService(),
        _secureStorage = SecureStorageService(),
        _httpClient = httpClient ?? http.Client();

  Future<Map<String, String>> _getAuthHeaders() async {
    final headers = _encryptionService.generateSecureHeaders(
      config.stripePublishableKey,
    );
    return {
      'Content-Type': 'application/json',
      'Authorization': 'Bearer ${config.stripePublishableKey}',
      ...headers,
    };
  }

  Future<String> createPaymentIntent({
    required double amount,
    required String currency,
    required String customerId,
    Map<String, dynamic>? metadata,
  }) async {
    try {
      final headers = await _getAuthHeaders();
      final response = await _httpClient.post(
        Uri.parse('${config.backendBaseUrl}/api/payments/create-intent'),
        headers: headers,
        body: jsonEncode({
          'amount': (amount * 100).toInt(),
          'currency': currency.toLowerCase(),
          'customer_id': customerId,
          'metadata': metadata ?? {},
        }),
      );

      if (response.statusCode == 200) {
        final data = jsonDecode(response.body);
        return data['client_secret'];
      } else {
        throw PaymentException(
          'Failed to create payment intent: ${response.statusCode}',
          code: 'CREATE_INTENT_FAILED',
        );
      }
    } catch (e) {
      if (e is PaymentException) rethrow;
      throw PaymentException(
        'Network error creating payment intent: $e',
        code: 'NETWORK_ERROR',
      );
    }
  }

  Future<String> createOrGetCustomer({
    required String userId,
    required String email,
    String? name,
  }) async {
    final existingId = await _secureStorage.getCustomerId(userId);
    if (existingId != null) return existingId;

    try {
      final headers = await _getAuthHeaders();
      final response = await _httpClient.post(
        Uri.parse('${config.backendBaseUrl}/api/payments/create-customer'),
        headers: headers,
        body: jsonEncode({
          'user_id': userId,
          'email': email,
          'name': name,
        }),
      );

      if (response.statusCode == 200) {
        final data = jsonDecode(response.body);
        final customerId = data['customer_id'] as String;
        await _secureStorage.saveCustomerId(userId, customerId);
        return customerId;
      } else {
        throw PaymentException(
          'Failed to create customer: ${response.statusCode}',
          code: 'CREATE_CUSTOMER_FAILED',
        );
      }
    } catch (e) {
      if (e is PaymentException) rethrow;
      throw PaymentException(
        'Network error creating customer: $e',
        code: 'NETWORK_ERROR',
      );
    }
  }

  Future<PaymentResult> confirmPayment({
    required String paymentIntentId,
    required String paymentMethodId,
  }) async {
    try {
      final headers = await _getAuthHeaders();
      final response = await _httpClient.post(
        Uri.parse('${config.backendBaseUrl}/api/payments/confirm'),
        headers: headers,
        body: jsonEncode({
          'payment_intent_id': paymentIntentId,
          'payment_method_id': paymentMethodId,
        }),
      );

      if (response.statusCode == 200) {
        final data = jsonDecode(response.body);
        return PaymentResult(
          success: data['status'] == 'succeeded',
          transactionId: data['transaction_id'],
          status: _mapStatus(data['status']),
          metadata: data['metadata'],
        );
      } else {
        final data = jsonDecode(response.body);
        return PaymentResult(
          success: false,
          errorMessage: data['error'] ?? 'Payment confirmation failed',
          status: PaymentStatus.failed,
        );
      }
    } catch (e) {
      return PaymentResult(
        success: false,
        errorMessage: 'Network error confirming payment: $e',
        status: PaymentStatus.failed,
      );
    }
  }

  Future<PaymentResult> processRefund({
    required String transactionId,
    double? amount,
    String? reason,
  }) async {
    try {
      final headers = await _getAuthHeaders();
      final body = <String, dynamic>{
        'transaction_id': transactionId,
        if (amount != null) 'amount': (amount * 100).toInt(),
        if (reason != null) 'reason': reason,
      };

      final response = await _httpClient.post(
        Uri.parse('${config.backendBaseUrl}/api/payments/refund'),
        headers: headers,
        body: jsonEncode(body),
      );

      if (response.statusCode == 200) {
        final data = jsonDecode(response.body);
        return PaymentResult(
          success: true,
          transactionId: data['refund_id'],
          status: PaymentStatus.refunded,
        );
      } else {
        return PaymentResult(
          success: false,
          errorMessage: 'Refund failed',
          status: PaymentStatus.failed,
        );
      }
    } catch (e) {
      return PaymentResult(
        success: false,
        errorMessage: 'Network error processing refund: $e',
        status: PaymentStatus.failed,
      );
    }
  }

  Future<bool> verifyReceipt({
    required String receiptData,
    required String platform,
  }) async {
    try {
      final headers = await _getAuthHeaders();
      final response = await _httpClient.post(
        Uri.parse('${config.backendBaseUrl}/api/payments/verify-receipt'),
        headers: headers,
        body: jsonEncode({
          'receipt_data': receiptData,
          'platform': platform,
        }),
      );

      if (response.statusCode == 200) {
        final data = jsonDecode(response.body);
        return data['valid'] == true;
      }
      return false;
    } catch (e) {
      return false;
    }
  }

  PaymentStatus _mapStatus(String? status) {
    switch (status) {
      case 'succeeded':
        return PaymentStatus.completed;
      case 'processing':
        return PaymentStatus.processing;
      case 'requires_action':
        return PaymentStatus.pending;
      case 'canceled':
        return PaymentStatus.cancelled;
      default:
        return PaymentStatus.failed;
    }
  }

  void dispose() {
    _httpClient.close();
  }
}


// lib/payment_module/services/in_app_purchase_service.dart

import 'dart:async';
import 'dart:io';
import 'package:in_app_purchase/in_app_purchase.dart';
import 'package:in_app_purchase_storekit/in_app_purchase_storekit.dart';
import 'package:in_app_purchase_android/in_app_purchase_android.dart';
import '../models/payment_models.dart';
import 'payment_gateway_service.dart';

class InAppPurchaseService {
  final InAppPurchase _iap = InAppPurchase.instance;
  final PaymentGatewayService _gatewayService;

  StreamSubscription<List<PurchaseDetails>>? _subscription;
  final StreamController<PaymentResult> _purchaseResultController =
      StreamController<PaymentResult>.broadcast();

  Stream<PaymentResult> get purchaseResultStream =>
      _purchaseResultController.stream;

  List<ProductDetails> _products = [];
  List<ProductDetails> get products => _products;

  bool _isAvailable = false;
  bool get isAvailable => _isAvailable;

  InAppPurchaseService({required PaymentGatewayService gatewayService})
      : _gatewayService = gatewayService;

  Future<void> initialize() async {
    _isAvailable = await _iap.isAvailable();
    if (!_isAvailable) return;

    if (Platform.isIOS) {
      final iosPlatformAddition =
          _iap.getPlatformAddition<InAppPurchaseStoreKitPlatformAddition>();
      await iosPlatformAddition.setDelegate(PaymentQueueDelegate());
    }

    _subscription = _iap.purchaseStream.listen(
      _handlePurchaseUpdates,
      onDone: () => _subscription?.cancel(),
      onError: (error) {
        _purchaseResultController.add(PaymentResult(
          success: false,
          errorMessage: 'Purchase stream error: $error',
          status: PaymentStatus.failed,
        ));
      },
    );
  }

  Future<void> loadProducts(Set<String> productIds) async {
    if (!_isAvailable) return;

    final response = await _iap.queryProductDetails(productIds);

    if (response.notFoundIDs.isNotEmpty) {
      print('Products not found: ${response.notFoundIDs}');
    }

    _products = response.productDetails;
  }

  Future<void> purchaseProduct(ProductDetails product) async {
    if (!_isAvailable) {
      _purchaseResultController.add(const PaymentResult(
        success: false,
        errorMessage: 'In-app purchases not available',
        status: PaymentStatus.failed,
      ));
      return;
    }

    final purchaseParam = PurchaseParam(productDetails: product);

    try {
      if (_isConsumable(product.id)) {
        await _iap.buyConsumable(purchaseParam: purchaseParam);
      } else {
        await _iap.buyNonConsumable(purchaseParam: purchaseParam);
      }
    } catch (e) {
      _purchaseResultController.add(PaymentResult(
        success: false,
        errorMessage: 'Purchase initiation failed: $e',
        status: PaymentStatus.failed,
      ));
    }
  }

  Future<void> restorePurchases() async {
    if (!_isAvailable) return;
    await _iap.restorePurchases();
  }

  Future<void> _handlePurchaseUpdates(
      List<PurchaseDetails> purchaseDetailsList) async {
    for (final purchase in purchaseDetailsList) {
      switch (purchase.status) {
        case PurchaseStatus.pending:
          _purchaseResultController.add(PaymentResult(
            success: false,
            transactionId: purchase.purchaseID,
            status: PaymentStatus.pending,
          ));
          break;

        case PurchaseStatus.purchased:
        case PurchaseStatus.restored:
          final valid = await _verifyPurchase(purchase);
          if (valid) {
            _purchaseResultController.add(PaymentResult(
              success: true,
              transactionId: purchase.purchaseID,
              status: purchase.status == PurchaseStatus.restored
                  ? PaymentStatus.completed
                  : PaymentStatus.completed,
              metadata: {
                'productId': purchase.productID,
                'restored': purchase.status == PurchaseStatus.restored,
              },
            ));
          } else {
            _purchaseResultController.add(PaymentResult(
              success: false,
              transactionId: purchase.purchaseID,
              errorMessage: 'Purchase verification failed',
              status: PaymentStatus.failed,
            ));
          }
          break;

        case PurchaseStatus.error:
          _purchaseResultController.add(PaymentResult(
            success: false,
            errorMessage: purchase.error?.message ?? 'Unknown purchase error',
            status: PaymentStatus.failed,
          ));
          break;

        case PurchaseStatus.canceled:
          _purchaseResultController.add(const PaymentResult(
            success: false,
            errorMessage: 'Purchase cancelled by user',
            status: PaymentStatus.cancelled,
          ));
          break;
      }

      if (purchase.pendingCompletePurchase) {
        await _iap.completePurchase(purchase);
      }
    }
  }

  Future<bool> _verifyPurchase(PurchaseDetails purchase) async {
    final receiptData = purchase.verificationData.serverVerificationData;
    final platform = Platform.isIOS ? 'ios' : 'android';

    return await _gatewayService.verifyReceipt(
      receiptData: receiptData,
      platform: platform,
    );
  }

  bool _isConsumable(String productId) {
    const consumableIds = {'coins_100', 'coins_500', 'coins_1000', 'gems_pack'};
    return consumableIds.contains(productId);
  }

  void dispose() {
    _subscription?.cancel();
    _purchaseResultController.close();
  }
}

class PaymentQueueDelegate implements SKPaymentQueueDelegateWrapper {
  @override
  bool shouldContinueTransaction(
      SKPaymentTransactionWrapper transaction, SKStorefrontWrapper storefront) {
    return true;
  }

  @override
  bool shouldShowPriceConsent() {
    return false;
  }
}


// lib/payment_module/services/mobile_wallet_service.dart

import 'dart:io';
import 'package:pay/pay.dart';
import '../config/payment_config.dart';
import '../models/payment_models.dart';
import 'payment_gateway_service.dart';

class MobileWalletService {
  final PaymentConfig config;
  final PaymentGatewayService _gatewayService;

  Pay? _payClient;
  bool _applePayAvailable = false;
  bool _googlePayAvailable = false;

  bool get applePayAvailable => _applePayAvailable;
  bool get googlePayAvailable => _googlePayAvailable;

  MobileWalletService({
    required this.config,
    required PaymentGatewayService gatewayService,
  }) : _gatewayService = gatewayService;

  Future<void> initialize() async {
    final paymentConfigurations = <PayProvider, PaymentConfiguration>{};

    if (Platform.isIOS) {
      paymentConfigurations[PayProvider.apple_pay] =
          PaymentConfiguration.fromJsonString(_applePayConfig());
      _applePayAvailable = true;
    } else if (Platform.isAndroid) {
      paymentConfigurations[PayProvider.google_pay] =
          PaymentConfiguration.fromJsonString(_googlePayConfig());
      _googlePayAvailable = true;
    }

    if (paymentConfigurations.isNotEmpty) {
      _payClient = Pay(paymentConfigurations);
    }

    if (Platform.isIOS) {
      try {
        final result = await _payClient?.userCanPay(PayProvider.apple_pay);
        _applePayAvailable = result ?? false;
      } catch (_) {
        _applePayAvailable = false;
      }
    } else if (Platform.isAndroid) {
      try {
        final result = await _payClient?.userCanPay(PayProvider.google_pay);
        _googlePayAvailable = result ?? false;
      } catch (_) {
        _googlePayAvailable = false;
      }
    }
  }

  Future<PaymentResult> processWalletPayment({
    required PaymentItem item,
    required String userId,
  }) async {
    if (_payClient == null) {
      return const PaymentResult(
        success: false,
        errorMessage: 'Mobile wallet not initialized',
        status: PaymentStatus.failed,
      );
    }

    try {
      final paymentItems = [
        PaymentItem2(
          label: item.name,
          amount: item.price.toStringAsFixed(2),
          status: PaymentItemStatus.final_price,
        ),
      ];

      final provider = Platform.isIOS
          ? PayProvider.apple_pay
          : PayProvider.google_pay;

      final result = await _payClient!.showPaymentSelector(
        provider,
        paymentItems,
      );

      final token = _extractPaymentToken(result);

      final customerId = await _gatewayService.createOrGetCustomer(
        userId: userId,
        email: result['email'] ?? '',
      );

      final clientSecret = await _gatewayService.createPaymentIntent(
        amount: item.price,
        currency: item.currency,
        customerId: customerId,
        metadata: {
          'item_id': item.id,
          'wallet_type': Platform.isIOS ? 'apple_pay' : 'google_pay',
        },
      );

      return await _gatewayService.confirmPayment(
        paymentIntentId: clientSecret,
        paymentMethodId: token,
      );
    } catch (e) {
      if (e.toString().contains('cancelled') ||
          e.toString().contains('canceled')) {
        return const PaymentResult(
          success: false,
          errorMessage: 'Payment cancelled by user',
          status: PaymentStatus.cancelled,
        );
      }
      return PaymentResult(
        success: false,
        errorMessage: 'Wallet payment failed: $e',
        status: PaymentStatus.failed,
      );
    }
  }

  String _extractPaymentToken(Map<String, dynamic> result) {
    if (Platform.isIOS) {
      return result['token'] ?? result['paymentData'] ?? '';
    } else {
      final paymentMethodData = result['paymentMethodData'];
      if (paymentMethodData is Map) {
        final tokenizationData = paymentMethodData['tokenizationData'];
        if (tokenizationData is Map) {
          return tokenizationData['token'] ?? '';
        }
      }
      return result['token'] ?? '';
    }
  }

  String _applePayConfig() {
    return '''
    {
      "provider": "apple_pay",
      "data": {
        "merchantIdentifier": "${config.merchantId}",
        "displayName": "${config.merchantName}",
        "merchantCapabilities": ["3DS", "debit", "credit"],
        "supportedNetworks": ${config.supportedNetworks.map((n) => '"$n"').toList()},
        "countryCode": "US",
        "currencyCode": "USD"
      }
    }
    ''';
  }

  String _googlePayConfig() {
    return '''
    {
      "provider": "google_pay",
      "data": {
        "environment": "${config.sandboxMode ? 'TEST' : 'PRODUCTION'}",
        "apiVersion": 2,
        "apiVersionMinor": 0,
        "allowedPaymentMethods": [
          {
            "type": "CARD",
            "parameters": {
              "allowedAuthMethods": ["PAN_ONLY", "CRYPTOGRAM_3DS"],
              "allowedCardNetworks": ${config.supportedNetworks.map((n) => '"${n.toUpperCase()}"').toList()}
            },
            "tokenizationSpecification": {
              "type": "PAYMENT_GATEWAY",
              "parameters": {
                "gateway": "stripe",
                "stripe:version": "2023-10-16",
                "stripe:publishableKey": "${config.stripePublishableKey}"
              }
            }
          }
        ],
        "merchantInfo": {
          "merchantId": "${config.merchantId}",
          "merchantName": "${config.merchantName}"
        },
        "transactionInfo": {
          "totalPriceStatus": "FINAL",
          "totalPrice": "0.00",
          "currencyCode": "USD",
          "countryCode": "US"
        }
      }
    }
    ''';
  }
}

