import 'dart:convert';
import 'package:http/http.dart' as http;
import '../config/payment_config.dart';
import '../models/payment_models.dart';
import 'encryption_service.dart';

class TransactionService {
  final PaymentConfig config;
  final EncryptionService _encryptionService;
  final http.Client _httpClient;

  final List<TransactionRecord> _localCache = [];

  TransactionService({
    required this.config,
    http.Client? httpClient,
  })  : _encryptionService = EncryptionService(),
        _httpClient = httpClient ?? http.Client();

  Future<TransactionRecord> createTransaction({
    required String userId,
    required PaymentItem item,
    required PaymentMethod method,
    required TransactionType type,
  }) async {
    final record = TransactionRecord(
      id: _encryptionService.generateNonce(16),
      userId: userId,
      item: item,
      method: method,
      status: PaymentStatus.pending,
      type: type,
      createdAt: DateTime.now(),
    );

    _localCache.add(record);

    try {
      final headers = _encryptionService.generateSecureHeaders(
        config.stripePublishableKey,
      );
      await _httpClient.post(
        Uri.parse('${config.backendBaseUrl}/api/transactions'),
        headers: {
          'Content-Type': 'application/json',
          ...headers,
        },
        body: jsonEncode(record.toJson()),
      );
    } catch (e) {
      print('Failed to sync transaction to server: $e');
    }

    return record;
  }

  Future<void> updateTransactionStatus({
    required String transactionId,
    required PaymentStatus status,
    String? gatewayTransactionId,
  }) async {
    final index = _localCache.indexWhere((t) => t.id == transactionId);
    if (index != -1) {
      final existing = _localCache[index];
      _localCache[index] = TransactionRecord(
        id: existing.id,
        userId: existing.userId,
        item: existing.item,
        method: existing.method,
        status: status,
        type: existing.type,
        createdAt: existing.createdAt,
        completedAt: status == PaymentStatus.completed ? DateTime.now() : null,
        gatewayTransactionId: gatewayTransactionId,
      );
    }

    try {
      final headers = _encryptionService.generateSecureHeaders(
        config.stripePublishableKey,
      );
      await _httpClient.patch(
        Uri.parse(
            '${config.backendBaseUrl}/api/transactions/$transactionId'),
        headers: {
          'Content-Type': 'application/json',
          ...headers,
        },
        body: jsonEncode({
          'status': status.name,
          'gateway_transaction_id': gatewayTransactionId,
        }),
      );
    } catch (e) {
      print('Failed to sync transaction status to server: $e');
    }
  }

  Future<List<TransactionRecord>> getTransactionHistory(String userId) async {
    try {
      final headers = _encryptionService.generateSecureHeaders(
        config.stripePublishableKey,
      );
      final response = await _httpClient.get(
        Uri.parse(
            '${config.backendBaseUrl}/api/transactions?user_id=$userId'),
        headers: {
          'Content-Type': 'application/json',
          ...headers,
        },
      );

      if (response.statusCode == 200) {
        final data = jsonDecode(response.body) as List;
        // Parse from server in production
        return _localCache.where((t) => t.userId == userId).toList();
      }
    } catch (e) {
      print('Failed to fetch transaction history: $e');
    }

    return _localCache.where((t) => t.userId == userId).toList();
  }

  void dispose() {
    _httpClient.close();
  }
}


// lib/payment_module/payment_module.dart

import 'dart:async';
import 'config/payment_config.dart';
import 'models/payment_models.dart';
import 'services/encryption_service.dart';
import 'services/in_app_purchase_service.dart';
import 'services/mobile_wallet_service.dart';
import 'services/payment_gateway_service.dart';
import 'services/secure_storage_service.dart';
import 'services/transaction_service.dart';

class PaymentModule {
  static PaymentModule? _instance;

  late final PaymentConfig config;
  late final PaymentGatewayService gatewayService;
  late final InAppPurchaseService inAppPurchaseService;
  late final MobileWalletService walletService;
  late final TransactionService transactionService;
  late final EncryptionService encryptionService;
  late final SecureStorageService secureStorageService;

  bool _initialized = false;
  bool get isInitialized => _initialized;

  PaymentModule._();

  factory PaymentModule() {
    _instance ??= PaymentModule._();
    return _instance!;
  }

  Future<void> initialize(PaymentConfig paymentConfig) async {
    if (_initialized) return;

    config = paymentConfig;
    encryptionService = EncryptionService();
    secureStorageService = SecureStorageService();

    gatewayService = PaymentGatewayService(config: config);
    transactionService = TransactionService(config: config);

    inAppPurchaseService = InAppPurchaseService(
      gatewayService: gatewayService,
    );
    await inAppPurchaseService.initialize();

    walletService = MobileWalletService(
      config: config,
      gatewayService: gatewayService,
    );
    await walletService.initialize();

    _initialized = true;
  }

  Future<PaymentResult> processCardPayment({
    required PaymentItem item,
    required String userId,
    required String email,
    String? name,
  }) async {
    _ensureInitialized();

    final transaction = await transactionService.createTransaction(
      userId: userId,
      item: item,
      method: PaymentMethod.creditCard,
      type: item.isSubscription
          ? TransactionType.subscription
          : TransactionType.purchase,
    );

    try {
      final customerId = await gatewayService.createOrGetCustomer(
        userId: userId,
        email: email,
        name: name,
      );

      final clientSecret = await gatewayService.createPaymentIntent(
        amount: item.price,
        currency: item.currency,
        customerId: customerId,
        metadata: {
          'item_id': item.id,
          'transaction_id': transaction.id,
        },
      );

      // In production, the card payment UI (Stripe Payment Sheet) handles
      // collecting card details and confirming. This returns the result.
      // For now, we return a pending state - the UI layer will handle
      // presenting the Stripe payment sheet.
      return PaymentResult(
        success: true,
        transactionId: transaction.id,
        status: PaymentStatus.processing,
        metadata: {
          'client_secret': clientSecret,
          'customer_id': customerId,
        },
      );
    } catch (e) {
      await transactionService.updateTransactionStatus(
        transactionId: transaction.id,
        status: PaymentStatus.failed,
      );

      return PaymentResult(
        success: false,
        transactionId: transaction.id,
        errorMessage: e.toString(),
        status: PaymentStatus.failed,
      );
    }
  }

  Future<PaymentResult> processWalletPayment({
    required PaymentItem item,
    required String userId,
  }) async {
    _ensureInitialized();

    final transaction = await transactionService.createTransaction(
      userId: userId,
      item: item,
      method: _getWalletMethod(),
      type: TransactionType.purchase,
    );

    final result = await walletService.processWalletPayment(
      item: item,
      userId: userId,
    );

    await transactionService.updateTransactionStatus(
      transactionId: transaction.id,
      status: result.status,
      gatewayTransactionId: result.transactionId,
    );

    return PaymentResult(
      success: result.success,
      transactionId: transaction.id,
      errorMessage: result.errorMessage,
      status: result.status,
      metadata: {
        ...?result.metadata,
        'local_transaction_id': transaction.id,
      },
    );
  }

  Future<void> purchaseInApp(String productId) async {
    _ensureInitialized();

    final product = inAppPurchaseService.products.firstWhere(
      (p) => p.id == productId,
      orElse: () => throw PaymentException(
        'Product not found: $productId',
        code: 'PRODUCT_NOT_FOUND',
      ),
    );

    await inAppPurchaseService.purchaseProduct(product);
  }

  Future<void> restorePurchases() async {
    _ensureInitialized();
    await inAppPurchaseService.restorePurchases();
  }

  Future<PaymentResult> processRefund({
    required String transactionId,
    double? amount,
    String? reason,
  }) async {
    _ensureInitialized();

    return await gatewayService.processRefund(
      transactionId: transactionId,
      amount: amount,
      reason: reason,
    );
  }

  Future<List<TransactionRecord>> getTransactionHistory(String userId) async {
    _ensureInitialized();
    return await transactionService.getTransactionHistory(userId);
  }

  Stream<PaymentResult> get inAppPurchaseResults =>
      inAppPurchaseService.purchaseResultStream;

  bool get isApplePayAvailable => walletService.applePayAvailable;
  bool get isGooglePayAvailable => walletService.googlePayAvailable;

  PaymentMethod _getWalletMethod() {
    if (walletService.applePayAvailable) return PaymentMethod.applePay;
    if (walletService.googlePayAvailable) return PaymentMethod.googlePay;
    return PaymentMethod.creditCard;
  }

  void _ensureInitialized() {
    if (!_initialized) {
      throw PaymentException(
        'PaymentModule not initialized. Call initialize() first.',
        code: 'NOT_INITIALIZED',
      );
    }
  }

  void dispose() {
    inAppPurchaseService.dispose();
    gatewayService.dispose();
    transactionService.dispose();
    _initialized = false;
    _instance = null;
  }
}


// lib/payment_module/exceptions/payment_exception.dart

class PaymentException implements Exception {
  final String message;
  final String? code;
  final dynamic originalError;

  const PaymentException(
    this.message, {
    this.code,
    this.originalError,
  });

  @override
  String toString() => 'PaymentException($code): $message';
}


// lib/payment_module/widgets/payment_button.dart

import 'package:flutter/material.dart';
import '../models/payment_models.dart';

class PaymentButton extends StatelessWidget {
  final PaymentMethod method;
  final VoidCallback onPressed;
  final bool isLoading;
  final bool isEnabled;

  const PaymentButton({
    super.key,
    required this.method,
    required this.onPressed,
    this.isLoading = false,
    this.isEnabled = true,
  });

  @override
  Widget build(BuildContext context) {
    return SizedBox(
      width: double.infinity,
      height: 52,
      child: ElevatedButton(
        onPressed: isEnabled && !isLoading ? onPressed : null,
        style: ElevatedButton.styleFrom(
          backgroundColor: _getButtonColor(),
          foregroundColor: Colors.white,
          shape: RoundedRectangleBorder(
            borderRadius: BorderRadius.circular(12),
          ),
          elevation: 2,
        ),
        child: isLoading
            ? const SizedBox(
                width: 24,
                height: 24,
                child: CircularProgressIndicator(
                  strokeWidth: 2,
                  valueColor: AlwaysStoppedAnimation<Color>(Colors.white),
                ),
              )
            : Row(
                mainAxisAlignment: MainAxisAlignment.center,
                children: [
                  Icon(_getIcon(), size: 24),
                  const SizedBox(width: 12),
                  Text(
                    _getLabel(),
                    style: const TextStyle(
                      fontSize: 16,
                      fontWeight: FontWeight.w600,
                    ),
                  ),
                ],
              ),
      ),
    );
  }

  Color _getButtonColor() {
    switch (method) {
      case PaymentMethod.applePay:
        return Colors.black;
      case PaymentMethod.googlePay:
        return Colors.white;
      case PaymentMethod.creditCard:
      case PaymentMethod.debitCard:
        return const Color(0xFF6772E5);
      case PaymentMethod.inAppPurchase:
        return Colors.blue;
    }
  }

  IconData _getIcon() {
    switch (method) {
      case PaymentMethod.applePay:
        return Icons.apple;
      case PaymentMethod.googlePay:
        return Icons.g_mobiledata;
      case PaymentMethod.creditCard:
        return Icons.credit_card;
      case PaymentMethod.debitCard:
        return Icons.credit_card;
      case PaymentMethod.inAppPurchase:
        return Icons.shopping_bag;
    }
  }

  String _getLabel() {
    switch (method) {
      case PaymentMethod.applePay:
        return 'Pay with Apple Pay';
      case PaymentMethod.googlePay:
        return 'Pay with Google Pay';
      case PaymentMethod.creditCard:
        return 'Pay with Card';
      case PaymentMethod.debitCard:
        return 'Pay with Debit Card';
      case PaymentMethod.inAppPurchase:
        return 'Purchase';
    }
  }
}


// lib/payment_module/widgets/payment_sheet.dart

import 'dart:async';
import 'package:flutter/material.dart';
import '../models/payment_models.dart';
import '../payment_module.dart';
import 'payment_button.dart';

class PaymentSheet extends StatefulWidget {
  final PaymentItem item;
  final String userId;
  final String userEmail;
  final String? userName;
  final Function(PaymentResult) onPaymentResult;
  final VoidCallback? onDismiss;

  const PaymentSheet({
    super.key,
    required this.item,
    required this.userId,
    required this.userEmail,
    this.userName,
    required this.onPaymentResult,
    this.onDismiss,
  });

  static Future<PaymentResult?> show({
    required BuildContext context,
    required PaymentItem item,
    required String userId,
    required String userEmail,
    String? userName,
  }) async {
    final completer = Completer<PaymentResult?>();

    await showModalBottomSheet<void>(
      context: context,
      isScrollControlled: true,
      backgroundColor: Colors.transparent,
      builder: (ctx) => PaymentSheet(
        item: item,
        userId: userId,
        userEmail: userEmail,
        userName: userName,
        onPaymentResult: (result) {
          completer.complete(result);
          Navigator.of(ctx).pop();
        },
        onDismiss: () {
          if (!completer.isCompleted) {
            completer.complete(null);
          }
        },
      ),
    );

    if (!completer.isCompleted) {
      completer.complete(null);
    }

    return completer.future;
  }

  @override
  State<PaymentSheet> createState() => _PaymentSheetState();
}

class _PaymentSheetState extends State<PaymentSheet> {
  final PaymentModule _paymentModule = PaymentModule();
  bool _isProcessing = false;
  String? _error;

  @override
  Widget build(BuildContext context) {
    return Container(
      decoration: const BoxDecoration(
        color: Colors.white,
        borderRadius: BorderRadius.vertical(top: Radius.circular(24)),
      ),
      padding: EdgeInsets.only(
        bottom: MediaQuery.of(context).viewInsets.bottom + 16,
      ),
      child: Column(
        mainAxisSize: MainAxisSize.min,
        children: [
          const SizedBox(height: 8),
          Container(
            width: 40,
            height: 4,
            decoration: BoxDecoration(
              color: Colors.grey[300],
              borderRadius: BorderRadius.circular(2),
            ),
          ),
          const SizedBox(height: 24),
          _buildHeader(),
          const SizedBox(height: 24),
          _buildPriceSection(),
          const SizedBox(height: 24),
          if (_error != null) _buildErrorBanner(),
          _buildPaymentOptions(),
          const SizedBox(height: 16),
          _buildSecurityNotice(),
          const SizedBox(height: 16),
        ],
      ),
    );
  }

  Widget _buildHeader() {
    return Padding(
      padding: const EdgeInsets.symmetric(horizontal: 24),
      child: Row(
        children: [
          Expanded(
            child: Column(
              crossAxisAlignment: CrossAxisAlignment.start,
              children: [
                Text(
                  widget.item.name,
                  style: const TextStyle(
                    fontSize: 20,
                    fontWeight: FontWeight.bold,
                  ),
                ),
                const SizedBox(height: 4),
                Text(
                  widget.item.description,
                  style: TextStyle(
                    fontSize: 14,
                    color: Colors.grey[600],
                  ),
                ),
              ],
            ),
          ),
          IconButton(
            onPressed: () {
              widget.onDismiss?.call();
              Navigator.of(context).pop();
            },
            icon: const Icon(Icons.close),
          ),
        ],
      ),
    );
  }

  Widget _buildPriceSection() {
    return Container(
      margin: const EdgeInsets.symmetric(horizontal: 24),
      padding: const EdgeInsets.all(16),
      decoration: BoxDecoration(
        color: Colors.grey[50],
        borderRadius: BorderRadius.circular(12),
        border: Border.all(color: Colors.grey[200]!),
      ),
      child: Row(
        mainAxisAlignment: MainAxisAlignment.spaceBetween,
        children: [
          const Text(
            'Total',
            style: TextStyle(
              fontSize: 16,
              fontWeight: FontWeight.w500,
            ),
          ),
          Text(
            '\$${widget.item.price.toStringAsFixed(2)} ${widget.item.currency}',
            style: const TextStyle(
              fontSize: 24,
              fontWeight: FontWeight.bold,
              color: Color(0xFF6772E5),
            ),
          ),
        ],
      ),
    );
  }

  Widget _buildErrorBanner() {
    return Container(
      margin: const EdgeInsets.symmetric(horizontal: 24),
      padding: const EdgeInsets.all(12),
      decoration: BoxDecoration(
        color: Colors.red[50],
        borderRadius: BorderRadius.circular(8),
        border: Border.all(color: Colors.red[200]!),
      ),
      child: Row(
        children: [
          Icon(Icons.error_outline, color: Colors.red[700], size: 20),
          const SizedBox(width: 8),
          Expanded(
            child: Text(
              _error!,
              style: TextStyle(color: Colors.red[700], fontSize: 13),
            ),
          ),
        ],
      ),
    );
  }

  Widget _buildPaymentOptions() {
    return Padding(
      padding: const EdgeInsets.symmetric(horizontal: 24),
      child: Column(
        children: [
          // Card payment
          PaymentButton(
            method: PaymentMethod.creditCard,
            isLoading: _isProcessing,
            onPressed: _processCardPayment,
          ),
          const SizedBox(height: 12),

          // Apple Pay
          if (_paymentModule.isApplePayAvailable) ...[
            PaymentButton(
              method: PaymentMethod.applePay,
              isLoading: _isProcessing,
              onPressed: _processWalletPayment,
            ),
            const SizedBox(height: 12),
          ],

          // Google Pay
          if (_paymentModule.isGooglePayAvailable) ...[
            PaymentButton(
              method: PaymentMethod.googlePay,
              isLoading: _isProcessing,
              onPressed: _processWalletPayment,
            ),
            const SizedBox(height: 12),
          ],
        ],
      ),
    );
  }

  Widget _buildSecurityNotice() {
    return Padding(
      padding: const EdgeInsets.symmetric(horizontal: 24),
      child: Row(
        mainAxisAlignment: MainAxisAlignment.center,
        children: [
          Icon(Icons.lock, size: 14, color: Colors.grey[500]),
          const SizedBox(width: 4),
          Text(
            'Secured by Stripe • PCI DSS Compliant',
            style: TextStyle(
              fontSize: 12,
              color: Colors.grey[500],
            ),
          ),
        ],
      ),
    );
  }

  Future<void> _processCardPayment() async {
    setState(() {
      _isProcessing = true;
      _error = null;
    });

    try {
      final result = await _paymentModule.processCardPayment(
        item: widget.item,
        userId: widget.userId,
        email: widget.userEmail,
        name: widget.userName,
      );

      widget.onPaymentResult(result);
    } catch (e) {
      setState(() {
        _error = e.toString();
      });
    } finally {
      if (mounted) {
        setState(() {
          _isProcessing = false;
        });
      }
    }
  }

  Future<void> _processWalletPayment() async {
    setState(() {
      _isProcessing = true;
      _error = null;
    });

    try {
      final result = await _paymentModule.processWalletPayment(
        item: widget.item,
        userId: widget.userId,
      );

      widget.onPaymentResult(result);
    } catch (e) {
      setState(() {
        _error = e.toString();
      });
    } finally {
      if (mounted) {
        setState(() {
          _isProcessing = false;
        });
      }
    }
  }
}


// lib/payment_module/widgets/transaction_history_widget.dart

import 'package:flutter/material.dart';
import '../models/payment_models.dart';
import '../payment_module.dart';

class TransactionHistoryWidget extends StatefulWidget {
  final String userId;

  const TransactionHistoryWidget({super.key, required this.userId});

  @override
  State<TransactionHistoryWidget> createState() =>
      _TransactionHistoryWidgetState();
}

class _TransactionHistoryWidgetState extends State<TransactionHistoryWidget> {
  final PaymentModule _paymentModule = PaymentModule();
  List<TransactionRecord> _transactions = [];
  bool _isLoading = true;

  @override
  void initState() {
    super.initState();
    _loadTransactions();
  }

  Future<void> _loadTransactions() async {
    setState(() => _isLoading = true);
    try {
      final transactions =
          await _paymentModule.getTransactionHistory(widget.userId);
      setState(() {
        _transactions = transactions;
        _isLoading = false;
      });
    } catch (e) {
      setState(() => _isLoading = false);
    }
  }

  @override
  Widget build(BuildContext context) {
    if (_isLoading) {
      return const Center(child: CircularProgressIndicator());
    }

    if (_transactions.isEmpty) {
      return Center(
        child: Column(
          mainAxisAlignment: MainAxisAlignment.center,
          children: [
            Icon(Icons.receipt_long, size: 64, color: Colors.grey[300]),
            const SizedBox(height: 16),
            Text(
              'No transactions yet',
              style: TextStyle(fontSize: 16, color: Colors.grey[500]),
            ),
          ],
        ),
      );
    }

    return RefreshIndicator(
      onRefresh: _loadTransactions,
      child: ListView.builder(
        itemCount: _transactions.length,
        padding: const EdgeInsets.all(16),
        itemBuilder: (context, index) {
          final transaction = _transactions[index];
          return _TransactionTile(transaction: transaction);
        },
      ),
    );
  }
}

class _TransactionTile extends StatelessWidget {
  final TransactionRecord transaction;

  const _TransactionTile({required this.transaction});

  @override
  Widget build(BuildContext context) {
    return Card(
      margin: const EdgeInsets.only(bottom: 8),
      shape: RoundedRectangleBorder(borderRadius: BorderRadius.circular(12)),
      child: ListTile(
        contentPadding: const EdgeInsets.all(16),
        leading: CircleAvatar(
          backgroundColor: _getStatusColor().withOpacity(0.1),
          child: Icon(
            _getStatusIcon(),
            color: _getStatusColor(),
            size: 20,
          ),
        ),
        title: Text(
          transaction.item.name,
          style: const TextStyle(fontWeight: FontWeight.w600),
        ),
        subtitle: Column(
          crossAxisAlignment: CrossAxisAlignment.start,
          children: [
            const SizedBox(height: 4),
            Text(
              _formatDate(transaction.createdAt),
              style: TextStyle(fontSize: 12, color: Colors.grey[500]),
            ),
            const SizedBox(height: 4),
            _StatusBadge(status: transaction.status),
          ],
        ),
        trailing: Text(
          '\$${transaction.item.price.toStringAsFixed(2)}',
          style: const TextStyle(
            fontSize: 16,
            fontWeight: FontWeight.bold,
          ),
        ),
      ),
    );
  }

  Color _getStatusColor() {
    switch (transaction.status) {
      case PaymentStatus.completed:
        return Colors.green;
      case PaymentStatus.pending:
      case PaymentStatus.processing:
        return Colors.orange;
      case PaymentStatus.failed:
        return Colors.red;
      case PaymentStatus.refunded:
        return Colors.blue;
      case PaymentStatus.cancelled:
        return Colors.grey;
    }
  }

  IconData _getStatusIcon() {
    switch (transaction.status) {
      case PaymentStatus.completed:
        return Icons.check_circle;
      case PaymentStatus.pending:
      case PaymentStatus.processing:
        return Icons.hourglass_bottom;
      case PaymentStatus.failed:
        return Icons.error;
      case PaymentStatus.refunded:
        return Icons.replay;
      case PaymentStatus.cancelled:
        return Icons.cancel;
    }
  }

  String _formatDate(DateTime date) {
    return '${date.day}/${date.month}/${date.year} ${date.hour}:${date.minute.toString().padLeft(2, '0')}';
  }
}

class _StatusBadge extends StatelessWidget {
  final PaymentStatus status;

  const _StatusBadge({required this.status});

  @override
  Widget build(BuildContext context) {
    return Container(
      padding: const EdgeInsets.symmetric(horizontal: 8, vertical: 2),
      decoration: BoxDecoration(
        color: _getColor().withOpacity(0.1),
        borderRadius: BorderRadius.circular(8),
      ),
      child: Text(
        status.name.toUpperCase(),
        style: TextStyle(
          fontSize: 10,
          fontWeight: FontWeight.w600,
          color: _getColor(),
        ),
      ),
    );
  }

  Color _getColor() {
    switch (status) {
      case PaymentStatus.completed:
        return Colors.green;
      case PaymentStatus.pending:
      case PaymentStatus.processing:
        return Colors.orange;
      case PaymentStatus.failed:
        return Colors.red;
      case PaymentStatus.refunded:
        return Colors.blue;
      case PaymentStatus.cancelled:
        return Colors.grey;
    }
  }
}


// lib/payment_module/widgets/in_app_purchase_store.dart

import 'dart:async';
import 'package:flutter/material.dart';
import 'package:in_app_purchase/in_app_purchase.dart';
import '../models/payment_models.dart';
import '../payment_module.dart';

class InAppPurchaseStore extends StatefulWidget {
  final Set<String> productIds;
  final String userId;
  final Function(PaymentResult)? onPurchaseResult;

  const InAppPurchaseStore({
    super.key,
    required this.productIds,
    required this.userId,
    this.onPurchaseResult,
  });

  @override
  State<InAppPurchaseStore> createState() => _InAppPurchaseStoreState();
}

class _InAppPurchaseStoreState extends State<InAppPurchaseStore> {
  final PaymentModule _paymentModule = PaymentModule();
  StreamSubscription<PaymentResult>? _subscription;
  bool _isLoading = true;
  String? _purchasingProductId;

  @override
  void initState() {
    super.initState();
    _initialize();
  }

  Future<void> _initialize() async {
    await _paymentModule.inAppPurchaseService.loadProducts(widget.productIds);

    _subscription = _paymentModule.inAppPurchaseResults.listen((result) {
      widget.onPurchaseResult?.call(result);
      setState(() => _purchasingProductId = null);

      if (result.success) {
        _showSnackBar('Purchase successful!', Colors.green);
      } else if (result.status != PaymentStatus.cancelled) {
        _showSnackBar(
          result.errorMessage ?? 'Purchase failed',
          Colors.red,
        );
      }
    });

    setState(() => _isLoading = false);
  }

  void _showSnackBar(String message, Color color) {
    if (mounted) {
      ScaffoldMessenger.of(context).showSnackBar(
        SnackBar(
          content: Text(message),
          backgroundColor: color,
          behavior: SnackBarBehavior.floating,
          shape: RoundedRectangleBorder(borderRadius: BorderRadius.circular(8)),
        ),
      );
    }
  }

  @override
  void dispose() {
    _subscription?.cancel();
    super.dispose();
  }

  @override
  Widget build(BuildContext context) {
    if (_isLoading) {
      return const Center(child: CircularProgressIndicator());
    }

    final products = _paymentModule.inAppPurchaseService.products;

    if (products.isEmpty) {
      return Center(
        child: Column(
          mainAxisAlignment: MainAxisAlignment.center,
          children: [
            Icon(Icons.store, size: 64, color: Colors.grey[300]),
            const SizedBox(height: 16),
            Text(
              'No products available',
              style: TextStyle(fontSize: 16, color: Colors.grey[500]),
            ),
          ],
        ),
      );
    }

    return Column(
      children: [
        Expanded(
          child: GridView.builder(
            padding: const EdgeInsets.all(16),
            gridDelegate: const SliverGridDelegateWithFixedCrossAxisCount(
              crossAxisCount: 2,
              childAspectRatio: 0.85,
              crossAxisSpacing: 12,
              mainAxisSpacing: 12,
            ),
            itemCount: products.length,
            itemBuilder: (context, index) {
              final product = products[index];
              return _ProductCard(
                product: product,
                isPurchasing: _purchasingProductId == product.id,
                onPurchase: () => _purchaseProduct(product),
              );
            },
          ),
        ),
        Padding(
          padding: const EdgeInsets.all(16),
          child: TextButton(
            onPressed: _restorePurchases,
            child: const Text('Restore Purchases'),
          ),
        ),
      ],
    );
  }

  Future<void> _purchaseProduct(ProductDetails product) async {
    setState(() => _purchasingProductId = product.id);
    await _paymentModule.purchaseInApp(product.id);
  }

  Future<void> _restorePurchases() async {
    await _paymentModule.restorePurchases();
    _showSnackBar('Restoring purchases...', Colors.blue);
  }
}

